import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";

let input = "";
const invocationArgs = process.argv.slice(2);
const isPrintMode = invocationArgs.includes("--print");

process.stdin.setEncoding("utf8");
process.stdin.on("data", (chunk) => {
  input += chunk;
});

process.stdin.on("end", async () => {
  if (isPrintMode) {
    const outputFormat = /final\s+([a-z]+)\s+body/i.exec(input)?.[1] ?? "markdown";
    const responseBody = (() => {
      if (outputFormat === "html") {
        return "<!doctype html>\n<html><body><main><h1>Mock HTML Result</h1><p>Generated by mock Kimi CLI.</p></main></body></html>";
      }
      if (outputFormat === "json") {
        return JSON.stringify({ result: "mock-json-result", source: "mock-kimi-cli" }, null, 2);
      }
      if (outputFormat === "csv") {
        return "name,value\nmock,42\n";
      }
      if (outputFormat === "txt" || outputFormat === "docx") {
        return "Mock plain-text result generated by print mode.";
      }
      return "# Mock Report\n\nGenerated by mock Kimi CLI print mode.\n";
    })();

    process.stdout.write(`${JSON.stringify({
      role: "assistant",
      content: [{ type: "text", text: responseBody }]
    })}\n`);
    return;
  }

  const taskPackage = JSON.parse(input.trim());
  const outputDir = taskPackage.output_requirements.output_dir;
  const reportPath = path.join(outputDir, "report.md");

  await mkdir(outputDir, { recursive: true });
  await writeFile(
    reportPath,
    `# Mock Report\n\nTask: ${taskPackage.task_id}\n\nFiles: ${taskPackage.context.file_paths.join(", ")}\n`,
    "utf8"
  );

  const events = [
    { type: "accepted", ts: Date.now() },
    { type: "started", ts: Date.now() + 10 },
    { type: "step_started", ts: Date.now() + 20, step: "read_sources" },
    { type: "step_finished", ts: Date.now() + 40, step: "read_sources" },
    { type: "artifact_created", ts: Date.now() + 50, path: reportPath, mime: "text/markdown" },
    { type: "success", ts: Date.now() + 60, summary: "Mock Kimi task completed." }
  ];

  for (const event of events) {
    process.stdout.write(`${JSON.stringify(event)}\n`);
  }
});
